CREATE TABLE IF NOT EXISTS `platform_settings` (
	`id` int AUTO_INCREMENT NOT NULL,
	`key` varchar(100) NOT NULL,
	`value` text NOT NULL,
	`description` text,
	`updatedAt` timestamp NOT NULL DEFAULT (now()) ON UPDATE CURRENT_TIMESTAMP,
	CONSTRAINT `platform_settings_id` PRIMARY KEY(`id`),
	CONSTRAINT `platform_settings_key_unique` UNIQUE(`key`)
);

ALTER TABLE `subscription_plans` ADD COLUMN IF NOT EXISTS `trialDays` int DEFAULT 14 NOT NULL;
ALTER TABLE `subscription_plans` ADD COLUMN IF NOT EXISTS `maxCallsPerMonth` int DEFAULT 500 NOT NULL;
ALTER TABLE `subscription_plans` ADD COLUMN IF NOT EXISTS `isPopular` enum('true','false') DEFAULT 'false';

